COPY package.json package-lock.json ./
RUN npm ci ${1:--only=production}
COPY . .

FROM ${1:node:20-alpine} AS builder
WORKDIR /app
COPY . .
RUN ${2:npm ci && npm run build}

FROM ${3:nginx:alpine}
COPY --from=builder ${4:/app/dist} ${5:/usr/share/nginx/html}
EXPOSE ${6:80}
CMD ["${7:nginx}", "${8:-g}", "${9:daemon off;}"]
